// src/services/api.js
const API_BASE_URL = 'http://localhost:5000/api';

// Helper function for API calls
async function fetchAPI(endpoint, options = {}) {
  const response = await fetch(`${API_BASE_URL}${endpoint}`, {
    headers: {
      'Content-Type': 'application/json',
      ...options.headers,
    },
    ...options,
  });

  if (!response.ok) {
    throw new Error(`API Error: ${response.status}`);
  }

  return response.json();
}

// Health check
export const checkHealth = async () => {
  return fetchAPI('/health');
};

// Courses
export const getCourses = async () => {
  return fetchAPI('/courses');
};

export const getFeaturedCourses = async (limit = 6) => {
  const data = await getCourses();
  return {
    courses: data.courses.slice(0, limit),
    total: data.courses.length
  };
};

// Notes
export const getNotes = async () => {
  return fetchAPI('/notes');
};

export const getTrendingNotes = async (limit = 5) => {
  const data = await getNotes();
  return data.notes.slice(0, limit);
};

// Stats
export const getStats = async () => {
  // For now, return mock stats
  // Later connect to /api/stats endpoint
  return {
    totalNotes: 500,
    totalPYQs: 1000,
    totalCourses: 50,
    totalDownloads: 2000
  };
};

export default {
  checkHealth,
  getCourses,
  getFeaturedCourses,
  getNotes,
  getTrendingNotes,
  getStats
};
